// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define ALPHABET 26
#define MAXLEN 200000

typedef struct State {
    int next[ALPHABET];
    int link;
    int len;
} State;

typedef struct SAM {
    State *st;
    int size;
    int last;
} SAM;

SAM *sam_create(int maxLen) {
    SAM *sam = (SAM *)malloc(sizeof(SAM));
    sam->st = (State *)calloc(2 * maxLen, sizeof(State));
    for (int i = 0; i < 2 * maxLen; ++i) for (int c = 0; c < ALPHABET; ++c) sam->st[i].next[c] = -1;
    sam->st[0].len = 0;
    sam->st[0].link = -1;
    sam->size = 1;
    sam->last = 0;
    return sam;
}

void sam_extend(SAM *sam, int ch) {
    int cur = sam->size++;
    sam->st[cur].len = sam->st[sam->last].len + 1;
    for (int i = 0; i < ALPHABET; ++i) sam->st[cur].next[i] = -1;
    int p = sam->last;
    while (p != -1 && sam->st[p].next[ch] == -1) {
        sam->st[p].next[ch] = cur;
        p = sam->st[p].link;
    }
    if (p == -1) {
        sam->st[cur].link = 0;
    } else {
        int q = sam->st[p].next[ch];
        if (sam->st[p].len + 1 == sam->st[q].len) {
            sam->st[cur].link = q;
        } else {
            int clone = sam->size++;
            sam->st[clone] = sam->st[q];
            sam->st[clone].len = sam->st[p].len + 1;
            while (p != -1 && sam->st[p].next[ch] == q) {
                sam->st[p].next[ch] = clone;
                p = sam->st[p].link;
            }
            sam->st[q].link = sam->st[cur].link = clone;
        }
    }
    sam->last = cur;
}

long long distinct_substrings(SAM *sam) {
    long long res = 0;
    for (int i = 1; i < sam->size; ++i) {
        res += sam->st[i].len - sam->st[sam->st[i].link].len;
    }
    return res;
}

long long common_substrings(SAM *sam, const char *s) {
    int n = strlen(s);
    int *best = (int *)calloc(sam->size, sizeof(int));
    int v = 0, l = 0;
    for (int i = 0; i < n; ++i) {
        int c = s[i] - 'a';
        while (v && sam->st[v].next[c] == -1) {
            v = sam->st[v].link;
            l = sam->st[v].len;
        }
        if (sam->st[v].next[c] != -1) {
            v = sam->st[v].next[c];
            ++l;
        } else {
            v = 0; l = 0;
        }
        if (best[v] < l) best[v] = l;
    }
    // propagate best values to suffix links in topological order (by length descending)
    int maxLen = 0;
    for (int i = 0; i < sam->size; ++i) if (sam->st[i].len > maxLen) maxLen = sam->st[i].len;
    int *cnt = (int *)calloc(maxLen + 1, sizeof(int));
    for (int i = 0; i < sam->size; ++i) ++cnt[sam->st[i].len];
    for (int i = 1; i <= maxLen; ++i) cnt[i] += cnt[i-1];
    int *order = (int *)malloc(sam->size * sizeof(int));
    for (int i = sam->size-1; i >=0; --i) order[--cnt[sam->st[i].len]] = i;
    for (int i = sam->size-1; i > 0; --i) {
        int v = order[i];
        int p = sam->st[v].link;
        if (p >=0 && best[v] > 0) {
            if (best[p] < (best[v] > sam->st[p].len ? sam->st[p].len : best[v]))
                best[p] = best[v] > sam->st[p].len ? sam->st[p].len : best[v];
        }
    }
    long long common = 0;
    for (int i = 1; i < sam->size; ++i) {
        int low = sam->st[sam->st[i].link].len;
        int high = sam->st[i].len;
        int mx = best[i];
        if (mx > low) {
            if (mx > high) mx = high;
            common += (mx - low);
        }
    }
    free(best);
    free(cnt);
    free(order);
    return common;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    char A[MAXLEN+5], B[MAXLEN+5];
    while (T--) {
        scanf("%s", A);
        scanf("%s", B);
        int lenA = strlen(A), lenB = strlen(B);
        SAM *samA = sam_create(lenA);
        for (int i = 0; i < lenA; ++i) sam_extend(samA, A[i]-'a');
        long long distinctA = distinct_substrings(samA);
        long long common = common_substrings(samA, B);
        // Build SAM for B to get its distinct count
        SAM *samB = sam_create(lenB);
        for (int i = 0; i < lenB; ++i) sam_extend(samB, B[i]-'a');
        long long distinctB = distinct_substrings(samB);
        long long answer = distinctA + distinctB - 2 * common;
        printf("%lld\n", answer);
        free(samA->st); free(samA);
        free(samB->st); free(samB);
    }
    return 0;
}

