// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;

struct SAM {
    struct State {int next[26]; int link; int len; State(){fill(begin(next), end(next), -1); link=-1; len=0;}};
    vector<State> st; int last;
    SAM(int maxLen){st.reserve(2*maxLen); st.push_back(State()); last=0;}
    void extend(int c){
        int cur = st.size(); st.push_back(State()); st[cur].len = st[last].len + 1;
        int p = last;
        while(p!=-1 && st[p].next[c]==-1){st[p].next[c]=cur; p=st[p].link;}
        if(p==-1) st[cur].link = 0;
        else{
            int q = st[p].next[c];
            if(st[p].len + 1 == st[q].len) st[cur].link = q;
            else{
                int clone = st.size(); st.push_back(st[q]); st[clone].len = st[p].len + 1;
                while(p!=-1 && st[p].next[c]==q){st[p].next[c]=clone; p=st[p].link;}
                st[q].link = st[cur].link = clone;
            }
        }
        last = cur;
    }
    long long distinct() const{
        long long ans=0; for(size_t i=1;i<st.size();++i) ans+= st[i].len - st[st[i].link].len; return ans;}
    long long common(const string &s) const{
        vector<int> best(st.size(),0);
        int v=0,l=0;
        for(char ch: s){int c=ch-'a';
            while(v && st[v].next[c]==-1){v=st[v].link; l=st[v].len;}
            if(st[v].next[c]!=-1){v=st[v].next[c]; ++l;} else {v=0; l=0;}
            best[v]=max(best[v],l);
        }
        // order states by length descending
        int maxLen=0; for(auto &stt:st) maxLen=max(maxLen,stt.len);
        vector<int> cnt(maxLen+1,0);
        for(auto &stt:st) ++cnt[stt.len];
        for(int i=1;i<=maxLen;++i) cnt[i]+=cnt[i-1];
        vector<int> order(st.size());
        for(int i=st.size()-1;i>=0;--i) order[--cnt[st[i].len]]=i;
        for(int i=st.size()-1;i>0;--i){int v=order[i]; int p=st[v].link; if(p!=-1){best[p]=max(best[p], min(best[v], st[p].len));}}
        long long common=0;
        for(size_t i=1;i<st.size();++i){int low=st[st[i].link].len; int high=st[i].len; int mx=best[i]; if(mx>low){if(mx>high) mx=high; common+= mx - low;}}
        return common;
    }
};

int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; while(T--){string A,B;cin>>A>>B; SAM samA(A.size()); for(char ch:A) samA.extend(ch-'a'); long long distinctA=samA.distinct(); long long common=samA.common(B); SAM samB(B.size()); for(char ch:B) samB.extend(ch-'a'); long long distinctB=samB.distinct(); long long ans=distinctA+distinctB-2*common; cout<<ans<<"\n"; }
    return 0; }
